import { Injectable } from '@angular/core';
import { environment } from '../environments/environment';

@Injectable({
  providedIn: 'root'
})
export class SearchHandlerService {
  apiKey: string = environment.apiKey;
  searchUrl = `https://www.googleapis.com/youtube/v3/search?key=${this.apiKey}&part=snippet&type=video&maxResults=50&q=dog`
  detailsUrl = `https://www.googleapis.com/youtube/v3/videos?part=id%2C%20snippet&key=${this.apiKey}&id=`
  async search(term: string, page: string){
    let apiCall = this.searchUrl;
    if(term) apiCall += "%20"+term;
    if(page!="firstPage") apiCall += `&pageToken=${page}`
    const response = await fetch(apiCall);
    const data = await response.json();
    return data;
  }

  async getVideoDetails(id: string){
    const response = await fetch(this.detailsUrl+id);
    const data = await response.json();
    return data;
  }

  constructor() { }
}
