import { Component, OnInit, HostListener } from '@angular/core';
import { SearchHandlerService } from '../search-handler.service';
import { Router, ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-main',
  templateUrl: './main.component.html',
  styleUrls: ['./main.component.scss'],
  providers: [SearchHandlerService]
})

export class MainComponent {
  
  title = 'yt-dog-video';
  results: any;
  term ="";
  searchConducted: boolean = false;
  showSuggestions: boolean = false;
  nextPage = "firtPage"; //token for the next page
  suggestedVideos: any;
  suggestionIdx = 0;
  suggestionLooper;

  //for                       Searching                             Getting path
  constructor(private search: SearchHandlerService, private router: Router, private route: ActivatedRoute){}

  ngOnInit(): void {
    this.term = this.route.snapshot.paramMap.get("term"); //handle search links
    if(this.term) this.doSearch();
    else this.unsearch();
  }

  searchRedirect(){
    this.router.navigate(['/s/'+this.term]);
    this.doSearch();
  }

  async doSearch(){
    if(!this.term) return;//empty search
    const res = await this.search.search(this.term, "firstPage");
    this.results = res.items;
    this.showSuggestions = false;
    this.searchConducted = true;
    console.log(this.results);
    this.nextPage = res.nextPageToken;
    clearInterval(this.suggestionLooper);
  }

  unsearch(){
    this.searchConducted = false;
    this.nextPage = "firstPage";
    this.getSuggestions();
  }

  //for infinite scrolling
  async continueSearch(){
    const res = await this.search.search(this.term, this.nextPage);
    console.log(res);
    this.results = this.results.concat(res.items);
    console.log(this.results);
  }

  async getSuggestions(){
    const res = await this.search.search("", "firstPage");
    this.suggestedVideos = res.items;
    this.showSuggestions = true;
    this.suggestionLooper = setInterval(()=>{
      this.suggestionIdx = ++this.suggestionIdx%this.suggestedVideos.length;
    },5000);
  }

  @HostListener("window:scroll", ["$event"])
    onWindowScroll() {
      //additional support for browsers
      let pos = (document.documentElement.scrollTop || document.body.scrollTop) + document.documentElement.offsetHeight;
      let max = document.documentElement.scrollHeight - 20; //start a bit from bottom for better UX
      if(pos >= max && this.searchConducted ) this.continueSearch();
  }

}
