import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from "@angular/router";
import { DomSanitizer } from '@angular/platform-browser';
import { SearchHandlerService } from '../search-handler.service';

@Component({
  selector: 'app-video',
  templateUrl: './video.component.html',
  styleUrls: ['./video.component.scss'],
  providers: [SearchHandlerService]
})

export class VideoComponent implements OnInit {

  videoID: string = '';
  video: any;
  term: string;

  constructor(private route: ActivatedRoute, private router: Router, private sanitizer: DomSanitizer, private search: SearchHandlerService) { }

  ngOnInit(): void {
    this.videoID = this.route.snapshot.paramMap.get("vid");
    this.getVideoDetails();
  }

  getVideoUrl(){
    return this.sanitizer.bypassSecurityTrustResourceUrl(`https://www.youtube.com/embed/${this.videoID}`);
  }

  async getVideoDetails(){
     this.video = await this.search.getVideoDetails(this.videoID);
  }

  searchRedirect(){
    if(!this.term) return;
    this.router.navigate(['/s/'+this.term]);
  }

}
